-- Chien -> humain, Fête, Volume 10

insert into public.message_templates (user_id,title,content,tone,is_system,is_manual_only,occasion,animal_type,animal_direction) values

(null,'Joyeuse fête. J''ai observé ta façon de vérifier l''appartement avant d''éteindre.',$$Joyeuse fête. J''ai observé ta façon de vérifier l''appartement avant d''éteindre.
Tu fais le tour des yeux. Le salon. La cuisine. L''entrée. Pas pour vérifier un oubli. Juste pour regarder. Pour voir l''espace qui a été vivant ce soir et qui redevient calme. Pour dire bonne nuit à la maison. J''ai fait pareil depuis mon coin. On est pareils. Joyeuse fête, mon humain préféré.
Avec reconnaissance de notre rituel commun de clôture visuelle et solidarité nocturne, — {prenom}, ton animal co-auteur de ce bonsoir 🏠$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu passes de l''état de fête à l''état de calme.',$$Joyeuse fête. J''ai observé comment tu passes de l''état de fête à l''état de calme.
Progressivement. Pas d''un coup. Les épaules d''abord qui descendent. Puis la voix qui baisse. Puis les gestes qui ralentissent. Cette décompression lente. Ce passage d''un état à l''autre sans rupture. Joyeuse fête, mon humain préféré.
Avec observation de ta décompression progressive et sa beauté organique, — {prenom}, ton animal témoin de tes transitions intérieures 🌙$$,'touching',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens emportent toujours exactement ce qu''ils avaient amené.',$$Joyeuse fête. Je comprends pas pourquoi les gens emportent toujours exactement ce qu''ils avaient amené.
Leurs manteaux. Leurs sacs. Leurs téléphones. Exactement ce qu''ils avaient en arrivant. Rien de la fête ne reste sur eux physiquement. Seulement des souvenirs. Peut-être que les souvenirs sont leur manteau de retour. Joyeuse fête, mon humain préféré.
Avec réflexion sur les souvenirs comme manteau de retour et sa jolie logique, — {prenom}, ton animal philosophe de ce qu''on emporte vraiment 🧥$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai étudié ta façon de choisir ce que tu allais manger en premier.',$$Joyeuse fête. J''ai étudié ta façon de choisir ce que tu allais manger en premier.
Tu regardes le buffet. Tu évalues. Tu prends quelque chose. Ce choix du premier. Cette décision qui dit quelque chose sur tes priorités. Sur ce que tu attendais le plus. J''ai observé ça. Et j''ai appris quelque chose sur toi. Joyeuse fête, mon humain préféré.
Avec révélation déduite de ton premier choix alimentaire et information précieuse collectée, — {prenom}, ton animal expert en lectures de premières sélections 🍽️$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé ta façon de regarder quelqu''un qui part pour la dernière fois de la soirée.',$$Joyeuse fête. J''ai observé ta façon de regarder quelqu''un qui part pour la dernière fois de la soirée.
Après le dernier au revoir. La porte fermée. Et toi tu regardes la porte encore une seconde. Comme si tu regardais encore la personne à travers. Cette seconde de prolongation du lien. Joyeuse fête, mon humain préféré.
Avec observation de ta seconde de prolongation du lien après la fermeture de la porte, — {prenom}, ton animal gardien de tes au revoir qui durent un peu plus 🚪$$,'touching',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu changes quand il ne reste plus que les proches.',$$Joyeuse fête. J''ai observé comment tu changes quand il ne reste plus que les proches.
Vers la fin quand les moins proches sont partis. Tu changes. Tu te détends différemment. Tu parles différemment. Tu ris différemment. Comme si tu pouvais être encore plus toi. Ce dernier cercle de la soirée est le meilleur. Joyeuse fête, mon humain préféré.
Avec observation de ton changement vers le dernier cercle intime et admiration pour cette version de toi, — {prenom}, ton animal pour qui cette version-là est la préférée 💛$$,'touching',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens arrivent au mauvais moment en cuisine.',$$Joyeuse fête. Je comprends pas pourquoi les gens arrivent au mauvais moment en cuisine.
Ce soir plusieurs fois quelqu''un est venu dans la cuisine exactement quand tu faisais quelque chose de délicat. Et toi tu as géré. Tu as souri. Tu as continué. Joyeuse fête, mon humain préféré.
Avec admiration pour ta grâce face aux intrusions culinaires mal timées, — {prenom}, ton animal qui ne serait pas aussi gracieux 🍳$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai mémorisé ta façon de prendre une grande respiration quand tout est fait.',$$Joyeuse fête. J''ai mémorisé ta façon de prendre une grande respiration quand tout est fait.
Ce moment. Après le dernier plat servi. Après le dernier verre rempli. Tu as pris une grande respiration. Profonde. Les yeux qui se ferment une seconde. Ce soupir de dépose. De transition du faire à l''être. Joyeuse fête, mon humain préféré.
Avec mémorisation de ta grande respiration de dépose et sa signification de transition, — {prenom}, ton animal gardien de tes soupirs de transition 😌$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé ta façon de te souvenir d''une chose importante à dire au dernier moment.',$$Joyeuse fête. J''ai observé ta façon de te souvenir d''une chose importante à dire au dernier moment.
Quelqu''un allait partir. Et tu as eu cette expression. Ce moment où quelque chose te revient. Et tu dis attends j''ai quelque chose à te dire. Et tu dis la chose. Et c''était la bonne chose à dire. Joyeuse fête, mon humain préféré.
Avec observation de ta mémoire de dernière minute et sa façon de ramener ce qui compte, — {prenom}, ton animal admirateur de tes rappels de l''essentiel 💭$$,'touching',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu faisais la transition entre hôte et toi-même après la fête.',$$Joyeuse fête. J''ai observé comment tu faisais la transition entre hôte et toi-même après la fête.
Progressivement. Les chaussures enlevées. La veste posée. La musique baissée. Ces gestes de déshabillage du rôle d''hôte. Ces façons de redevenir toi. Joyeuse fête, mon humain préféré.
Avec observation de ton déshabillage progressif du rôle d''hôte et ton retour à toi, — {prenom}, ton animal pour qui cette version-là est la préférée aussi 👤$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens disent qu''ils vont aider et partent quand même.',$$Joyeuse fête. Je comprends pas pourquoi les gens disent qu''ils vont aider et partent quand même.
Ce soir deux personnes ont dit qu''elles pouvaient rester pour aider à ranger. Et sont parties. Peut-être que proposer c''est une façon de ne pas se sentir coupable de partir. Et que la réponse non ça va merci est ce que tout le monde voulait. Joyeuse fête, mon humain préféré.
Avec compréhension de la danse entre proposer d''aider et partir et sa logique sociale, — {prenom}, ton animal décrypteur des codes de départ 🎭$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai étudié ta façon de poser tes couverts quand tu as fini de manger.',$$Joyeuse fête. J''ai étudié ta façon de poser tes couverts quand tu as fini de manger.
Posés côte à côte. Nets. Sur le bord de l''assiette. Ce geste universel qui dit j''ai fini. Cette façon de signaler sans mot. De communiquer avec des objets. Ce langage des couverts que tout le monde comprend et que personne n''a appris formellement. Joyeuse fête, mon humain préféré.
Avec observation de ton langage des couverts et admiration pour sa clarté universelle, — {prenom}, ton animal fasciné par les langages non verbaux 🍴$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé ta façon de regarder l''heure sans que ça se voie.',$$Joyeuse fête. J''ai observé ta façon de regarder l''heure sans que ça se voie.
Un regard rapide. Vers le téléphone ou l''heure quelque part. Tête pas vraiment tournée. Juste les yeux. Puis retour à la conversation. Ce soir j''ai compté quatre fois. Joyeuse fête, mon humain préféré.
Avec quatre regards discrets vers l''heure comptés et leur signification de gestion du temps, — {prenom}, ton animal observateur de tes vérifications invisibles ⌚$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu te comportes différemment avec les gens que tu vois rarement.',$$Joyeuse fête. J''ai observé comment tu te comportes différemment avec les gens que tu vois rarement.
Tu les écoutes plus longtemps. Tu poses plus de questions. Tu as cette curiosité sincère pour ce qu''ils ont vécu depuis la dernière fois. Comme si la rareté des rencontres rendait chaque moment plus précieux. Joyeuse fête, mon humain préféré.
Avec observation de ta façon de valoriser la rareté des rencontres et sa signification, — {prenom}, ton animal admirateur de ta présence accrue pour les rares 🤝$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens commentent la météo en arrivant.',$$Joyeuse fête. Je comprends pas pourquoi les gens commentent la météo en arrivant.
Ils entrent. Et la première chose. Il fait beau. Ou il pleut. Comme si le temps dehors était une information urgente à partager à l''intérieur. Peut-être que c''est une façon de se situer. De créer une transition entre dehors et dedans. Joyeuse fête, mon humain préféré.
Avec compréhension de la météo d''entrée comme transition entre dehors et dedans, — {prenom}, ton animal dont la transition entrée est plus olfactive 🌦️$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai mémorisé ta façon d''accepter les félicitations pour la soirée.',$$Joyeuse fête. J''ai mémorisé ta façon d''accepter les félicitations pour la soirée.
Simplement. Sans minimiser excessivement. Tu remercies. Tu dis que tu es content que ce soit bien. Tu souris. Cette façon d''accepter que tu as bien fait quelque chose. Sans fausse modestie. Sans excès de fierté. Joyeuse fête, mon humain préféré.
Avec admiration pour ton accueil juste des félicitations sans excès dans aucun sens, — {prenom}, ton animal témoin de ton rapport sain à ce que tu fais bien 🌟$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé ta façon de ranger ton tablier avec soin à la fin.',$$Joyeuse fête. J''ai observé ta façon de ranger ton tablier avec soin à la fin.
Plié. Proprement. À sa place. Pas jeté. Pas froissé. Ce soin pour quelque chose qui a travaillé ce soir. Cette façon de ranger l''outil avec respect après qu''il t''a servi. Joyeuse fête, mon humain préféré.
Avec observation de ton soin pour le tablier qui t''a servi et ce qu''il dit de toi, — {prenom}, ton animal attentif à ta façon de traiter les choses qui ont travaillé pour toi 👨‍🍳$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu te souviens de détails sur chaque invité.',$$Joyeuse fête. J''ai observé comment tu te souviens de détails sur chaque invité.
Tu t''en souviens. Du prénom de leur enfant. De leur situation. De quelque chose qu''ils t''avaient dit la dernière fois. Et tu le places dans la conversation naturellement. Cette mémoire affective. Cette façon de dire à chacun tu m''importes assez pour que je me souvienne. Joyeuse fête, mon humain préféré.
Avec admiration pour ta mémoire affective des détails de chaque personne, — {prenom}, ton animal témoin de ton attention aux autres dans le temps 🧠$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens restent encore après avoir dit au revoir trois fois.',$$Joyeuse fête. Je comprends pas pourquoi les gens restent encore après avoir dit au revoir trois fois.
On va y aller. Puis encore une chose. Puis vraiment on y va. Puis encore cinq minutes. Ces au revoir qui n''en finissent pas. Peut-être que c''est la meilleure partie. Quand on a décidé de partir mais qu''on part pas encore. Joyeuse fête, mon humain préféré.
Avec compréhension des au revoir prolongés comme temps suspendu de grâce, — {prenom}, ton animal fasciné par les états entre deux états 🎭$$,'humorous',true,false,'nameday','chien','from'),

(null,'Ce moment où tu réalises que ta fête était vraiment réussie.',$$Ce moment où tu réalises que ta fête était vraiment réussie.
C''est après. Quand tout le monde est parti. Quand tu t''assieds. Quand le silence revient. Et là quelque chose arrive. Une certitude tranquille. Que c''était bien. Vraiment bien. Que les gens sont partis contents. Que tu as créé quelque chose ce soir. Ce moment-là c''est le meilleur moment de la fête. Et je suis là pour le partager avec toi. Joyeuse fête, mon humain préféré.
Avec présence partagée dans ton moment de réalisation que c''était réussi, — {prenom}, ton animal pour le meilleur moment qui arrive après que tout le monde est parti ❤️$$,'touching',true,false,'nameday','chien','from')

on conflict do nothing;
